  "API_CHANGE",
  "GUARD_REMOVED",
  "LOGIC_CHANGE",
  "DELETED_FUNCTION",
  "NEW_FUNCTION",
  "REFACTOR",
  "COSMETIC",
  "UNCLASSIFIED"
