import * as fs56 from "fs";
import * as path71 from "path";
var EXT_MAP = {
  python: ".py",
  py: ".py",
  powershell: ".ps1",
  ps1: ".ps1",
  pwsh: ".ps1",
  javascript: ".js",
  js: ".js",
  typescript: ".ts",
  ts: ".ts",
  bash: ".sh",
  sh: ".sh",
  json: ".json",
  yaml: ".yaml",
  yml: ".yaml",
  xml: ".xml",
  html: ".html",
  css: ".css",
  sql: ".sql",
  pester: ".Tests.ps1",
  test: ".Tests.ps1",
  "": ".txt"
};
function extractFilename(code, language, index) {
  const lines = code.trim().split(`
`);
  const ext = EXT_MAP[language.toLowerCase()] ?? ".txt";
  if (lines.length > 0) {
    const firstLine = lines[0].trim();
    const filenameMatch = firstLine.match(/^[#/]+\s*filename[:\s]+(\S+\.\w+)/i);
    if (filenameMatch) {
      return filenameMatch[1];
    }
    const bareMatch = firstLine.match(/^[#/]+\s*(\w+\.\w+)\s*$/);
    if (bareMatch) {
      return bareMatch[1];
    }
  }
  for (const line of lines.slice(0, 5)) {
    const defMatch = line.match(/^(?:def\s+|class\s+)(\w+)/);
    if (defMatch && !defMatch[1].startsWith("_")) {
      return `${defMatch[1]}${ext}`;
    }
    const psMatch = line.match(/^function\s+([\w-]+)/i);
    if (psMatch) {
      return `${psMatch[1]}${ext}`;
    }
  }
  const timestamp = new Date().toISOString().replace(/[:.]/g, "-").slice(0, 19);
  return `output_${index + 1}_${timestamp}${ext}`;
}
var extract_code_blocks = createSwarmTool({
  description: "Extract code blocks from text content and save them to files. " + "Parses markdown-style code fences (```language...```) and saves each block. " + "Automatically determines filenames from comments or function names.",
  args: {
    content: tool.schema.string().describe("Text content containing code blocks to extract"),
    output_dir: tool.schema.string().optional().describe("Directory to save files (defaults to current directory)"),
    prefix: tool.schema.string().optional().describe("Optional prefix for generated filenames")
  },
  execute: async (args2, directory) => {
    const { content, output_dir, prefix } = args2;
    const targetDir = output_dir || directory;
    if (!fs56.existsSync(targetDir)) {
      fs56.mkdirSync(targetDir, { recursive: true });
    }
    if (!content) {
      return "Error: content is required";
    }
    const pattern = /```(\w*)\n([\s\S]*?)```/g;
    const matches = [...content.matchAll(pattern)];
    if (matches.length === 0) {
      return "No code blocks found in content.";
    }
    const savedFiles = [];
    const errors5 = [];
    for (let i2 = 0;i2 < matches.length; i2++) {
      const [, language, code] = matches[i2];
      let filename = extractFilename(code, language, i2);
      if (prefix) {
        filename = `${prefix}_${filename}`;
      }
      let filepath = path71.join(targetDir, filename);
      const base = path71.basename(filepath, path71.extname(filepath));
      const ext = path71.extname(filepath);
      let counter = 1;
      while (fs56.existsSync(filepath)) {
        filepath = path71.join(targetDir, `${base}_${counter}${ext}`);
        counter++;
      }
      try {
        fs56.writeFileSync(filepath, code.trim(), "utf-8");
        savedFiles.push(filepath);
      } catch (error93) {
        errors5.push(`Failed to save ${filename}: ${error93 instanceof Error ? error93.message : String(error93)}`);
      }
    }
    let result = `Extracted ${savedFiles.length} file(s):
`;
    for (const file3 of savedFiles) {
      result += `  - ${file3}
`;
    }
    if (errors5.length > 0) {
      result += `
Errors:
`;
      for (const err2 of errors5) {
        result += `  - ${err2}
`;
      }
    }
    return result;
  }
});
