async function runComposerAudit(directory) {
  const command = ["composer", "audit", "--locked", "--format=json"];
  if (!isCommandAvailable("composer")) {
    warn("[pkg-audit] composer not found, skipping Composer audit");
    return {
      ecosystem: "composer",
      command,
      findings: [],
      criticalCount: 0,
      highCount: 0,
      totalCount: 0,
      clean: true,
      note: "composer not installed or not on PATH"
    };
  }
  try {
    const proc = Bun.spawn(command, {
      stdout: "pipe",
      stderr: "pipe",
      cwd: directory
    });
    const timeoutPromise = new Promise((resolve29) => setTimeout(() => resolve29("timeout"), AUDIT_TIMEOUT_MS));
    const result = await Promise.race([
      Promise.all([
        new Response(proc.stdout).text(),
        new Response(proc.stderr).text()
      ]).then(([stdout2, stderr]) => ({ stdout: stdout2, stderr })),
      timeoutPromise
    ]);
    if (result === "timeout") {
      proc.kill();
      return {
        ecosystem: "composer",
        command,
        findings: [],
        criticalCount: 0,
        highCount: 0,
        totalCount: 0,
        clean: true,
        note: `composer audit timed out after ${AUDIT_TIMEOUT_MS / 1000}s`
      };
    }
    let { stdout } = result;
    if (stdout.length > MAX_OUTPUT_BYTES5) {
      stdout = stdout.slice(0, MAX_OUTPUT_BYTES5);
    }
    const exitCode = await proc.exited;
    const hasVulnerabilities = (exitCode & 1) !== 0;
    const hasAbandoned = (exitCode & 2) !== 0;
    if (exitCode === 0) {
      return {
        ecosystem: "composer",
        command,
        findings: [],
        criticalCount: 0,
        highCount: 0,
        totalCount: 0,
        clean: true
      };
    }
    if (hasVulnerabilities && !stdout.trim()) {
      return {
        ecosystem: "composer",
        command,
        findings: [],
        criticalCount: 0,
        highCount: 0,
        totalCount: 0,
        clean: false,
        note: `composer audit returned exit code ${exitCode} indicating vulnerabilities but produced no output`
      };
    }
    let parsed;
    try {
      parsed = JSON.parse(stdout || "{}");
    } catch {
      return {
        ecosystem: "composer",
        command,
        findings: [],
        criticalCount: 0,
        highCount: 0,
        totalCount: 0,
        clean: !hasVulnerabilities,
        note: `composer audit returned exit code ${exitCode} but output was not valid JSON`
      };
    }
    if (!hasVulnerabilities && hasAbandoned) {
      const abandonedList = Object.keys(parsed.abandoned ?? {});
      return {
        ecosystem: "composer",
        command,
        findings: [],
        criticalCount: 0,
        highCount: 0,
        totalCount: 0,
        clean: true,
        note: abandonedList.length > 0 ? `Abandoned packages detected: ${abandonedList.join(", ")}` : "composer audit exit 2 (abandoned packages)"
      };
    }
    const findings = [];
    for (const advisories of Object.values(parsed.advisories ?? {})) {
      for (const advisory of advisories) {
        const hasCve = Boolean(advisory.cve?.trim());
        findings.push({
          package: advisory.packageName,
          installedVersion: "see composer.lock",
          patchedVersion: null,
          severity: hasCve ? "high" : "moderate",
          title: advisory.title,
          cve: advisory.cve || null,
          url: advisory.link || null
        });
      }
    }
    const criticalCount = findings.filter((f) => f.severity === "critical").length;
    const highCount = findings.filter((f) => f.severity === "high").length;
    const abandonedNote = hasAbandoned && Object.keys(parsed.abandoned ?? {}).length > 0 ? ` Also abandoned: ${Object.keys(parsed.abandoned).join(", ")}` : "";
    return {
      ecosystem: "composer",
      command,
      findings,
      criticalCount,
      highCount,
      totalCount: findings.length,
      clean: false,
      ...abandonedNote ? { note: abandonedNote.trim() } : {}
    };
  } catch (error93) {
    return {
      ecosystem: "composer",
      command,
      findings: [],
      criticalCount: 0,
      highCount: 0,
      totalCount: 0,
      clean: true,
      note: `composer audit error: ${error93 instanceof Error ? error93.message : String(error93)}`
    };
  }
}
async function runAutoAudit(directory) {
  const ecosystems = detectEcosystems(directory);
  if (ecosystems.length === 0) {
    return {
      ecosystems: [],
      findings: [],
      criticalCount: 0,
      highCount: 0,
      totalCount: 0,
      clean: true
    };
  }
  const results = [];
  for (const eco of ecosystems) {
    switch (eco) {
      case "npm":
        results.push(await runNpmAudit(directory));
        break;
      case "pip":
        results.push(await runPipAudit(directory));
        break;
      case "cargo":
        results.push(await runCargoAudit(directory));
        break;
      case "go":
        results.push(await runGoAudit(directory));
        break;
      case "dotnet":
        results.push(await runDotnetAudit(directory));
        break;
      case "ruby":
        results.push(await runBundleAudit(directory));
        break;
      case "dart":
        results.push(await runDartAudit(directory));
        break;
      case "composer":
        results.push(await runComposerAudit(directory));
        break;
    }
  }
  const allFindings = [];
  let totalCritical = 0;
  let totalHigh = 0;
  for (const result of results) {
    allFindings.push(...result.findings);
    totalCritical += result.criticalCount;
    totalHigh += result.highCount;
  }
  return {
    ecosystems,
    findings: allFindings,
    criticalCount: totalCritical,
    highCount: totalHigh,
    totalCount: allFindings.length,
    clean: allFindings.length === 0
  };
}
var pkg_audit = createSwarmTool({
  description: 'Run package manager security audit (npm, pip, cargo, go, dotnet, ruby, dart) and return structured CVE data. Use ecosystem to specify which package manager, or "auto" to detect from project files.',
  args: {
    ecosystem: tool.schema.enum([
      "auto",
      "npm",
      "pip",
      "cargo",
      "go",
      "dotnet",
      "ruby",
      "dart",
      "composer"
    ]).default("auto").describe('Package ecosystem to audit: "auto" (detect from project files), "npm", "pip", "cargo", "go" (govulncheck), "dotnet" (dotnet list package), "ruby" (bundle-audit), "dart" (dart pub outdated), or "composer" (Composer/PHP)')
  },
  async execute(args2, directory) {
    if (!validateArgs3(args2)) {
      const errorResult = {
        error: 'Invalid arguments: ecosystem must be "auto", "npm", "pip", "cargo", "go", "dotnet", "ruby", "dart", or "composer"'
      };
      return JSON.stringify(errorResult, null, 2);
    }
    if (!directory || typeof directory !== "string" || directory.trim() === "") {
      const errorResult = {
        error: "project directory is required but was not provided"
      };
      return JSON.stringify(errorResult, null, 2);
    }
    const obj = args2;
    const ecosystem = obj.ecosystem || "auto";
    let result;
    switch (ecosystem) {
      case "auto":
        result = await runAutoAudit(directory);
        break;
      case "npm":
        result = await runNpmAudit(directory);
        break;
      case "pip":
        result = await runPipAudit(directory);
        break;
      case "cargo":
        result = await runCargoAudit(directory);
        break;
      case "go":
        result = await runGoAudit(directory);
        break;
      case "dotnet":
        result = await runDotnetAudit(directory);
        break;
      case "ruby":
        result = await runBundleAudit(directory);
        break;
      case "dart":
        result = await runDartAudit(directory);
        break;
      case "composer":
        result = await runComposerAudit(directory);
        break;
    }
    return JSON.stringify(result, null, 2);
  }
});
