    const paginatedContent = paginatedLines.join(`
`);
    const headerStart = startLine + 1;
    const headerEnd = endLine;
    const rangeHeader = `--- Lines ${headerStart}-${headerEnd} of ${totalLines} ---`;
    let response = `${rangeHeader}
${paginatedContent}`;
